                      : $flags eq 'm' ? qr/$clean_pattern/m
                      : $flags eq 's' ? qr/$clean_pattern/s
                      : $flags eq 'x' ? qr/$clean_pattern/x
                      : $flags eq 'im'  ? qr/$clean_pattern/im
                      : $flags eq 'is'  ? qr/$clean_pattern/is
