# Add a named validation pattern
sub add_pattern {
    my ($self, $name, $pattern, %opts) = @_;

    if (!defined $name || $name eq '') {
        warn "WARNING: Pattern name is required\n";
        return 0;
    }

    # Sanitize the name
    $name =~ s/[^a-zA-Z0-9_-]//g;

    my $compiled = $self->compile_pattern($pattern, %opts);
    if ($compiled) {
        $self->{patterns}{$name} = $pattern;
        $self->{compiled}{$name} = $compiled;
        return 1;
    }
    return 0;
}

# Validate a string against a named pattern
sub validate {
    my ($self, $name, $input) = @_;

    if (!exists $self->{compiled}{$name}) {
        warn "WARNING: No pattern registered with name '$name'\n";
        return { valid => 0, error => "Unknown pattern: $name" };
    }

    if (!defined $input) {
        return { valid => 0, error => "Input is undefined" };
    }

    if (length($input) > $self->{max_input_len}) {
        return {
            valid => 0,
            error => "Input exceeds maximum length of $self->{max_input_len}",
        };
    }

    my $regex = $self->{compiled}{$name};
    my $matched = 0;
    my @captures;

    # Use eval with timeout to protect against ReDoS
    {
        local $@;
        local $SIG{ALRM} = sub { die "Regex matching timed out (possible ReDoS)\n" };
        eval {
            alarm(COMPILE_TIMEOUT);
            if (@captures = ($input =~ $regex)) {
                $matched = 1;
            }
            alarm(0);
        };
        alarm(0);

        if ($@) {
            my $msg = "Error during matching: $@";
            chomp $msg;
            push @{$self->{errors}}, $msg;
            return { valid => 0, error => $msg };
        }
    }

    return {
        valid    => $matched,
        captures => $matched ? \@captures : [],
        pattern  => $self->{patterns}{$name},
        input    => $input,
    };
}

# Validate against an ad-hoc pattern (not pre-registered)
sub validate_adhoc {
    my ($self, $pattern, $input, %opts) = @_;

    my $compiled = $self->compile_pattern($pattern, %opts);
    if (!$compiled) {
