# Load patterns from a configuration file
# Format: name<TAB>pattern<TAB>flags (flags optional)
# Lines starting with # are comments
sub load_config {
    my ($self, $file) = @_;

    if (!defined $file || !-f $file) {
        warn "WARNING: Config file '$file' not found\n";
        return 0;
    }

    open my $fh, '<', $file or do {
        warn "WARNING: Cannot open config file '$file': $!\n";
        return 0;
    };

    my $count = 0;
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/;   # Skip comments
        next if $line =~ /^\s*$/;   # Skip blank lines

        my ($name, $pattern, $flags) = split /\t/, $line, 3;
        $flags //= '';
        $flags =~ s/\s+//g;

        if ($self->add_pattern($name, $pattern, flags => $flags)) {
            $count++;
        }
        else {
            warn "WARNING: Failed to load pattern '$name' from config\n";
        }
    }

    close $fh;
    print "Loaded $count patterns from '$file'\n";
    return $count;
}

# List all registered patterns
sub list_patterns {
    my ($self) = @_;
    my @names = sort keys %{$self->{patterns}};
    return @names;
}

# Get recent errors
