# ============================================================================
# Interactive mode
# ============================================================================
sub run_interactive {
    my ($validator) = @_;

    print "=" x 60, "\n";
    print "Flexible Validation System - Interactive Mode\n";
    print "=" x 60, "\n";
    print "Commands:\n";
    print "  list              - List all registered patterns\n";
    print "  add <name>        - Add a new pattern\n";
    print "  validate <name>   - Validate input against named pattern\n";
    print "  adhoc             - Validate with an ad-hoc pattern\n";
    print "  errors            - Show recent errors\n";
    print "  quit              - Exit\n";
    print "=" x 60, "\n\n";

    while (1) {
        print "command> ";
        my $cmd = <STDIN>;
        last unless defined $cmd;
        chomp $cmd;
        $cmd =~ s/^\s+|\s+$//g;

        next if $cmd eq '';

        if ($cmd eq 'quit' || $cmd eq 'exit' || $cmd eq 'q') {
            print "Goodbye!\n";
            last;
        }
        elsif ($cmd eq 'list') {
            my @names = $validator->list_patterns;
            if (@names) {
                print "Registered patterns:\n";
                for my $name (@names) {
                    printf "  %-15s  /%s/\n", $name, $validator->{patterns}{$name};
                }
            }
            else {
                print "No patterns registered.\n";
            }
        }
        elsif ($cmd =~ /^add\s+(\S+)/) {
            my $name = $1;
            print "Enter regex pattern: ";
            my $pattern = <STDIN>;
            last unless defined $pattern;
            chomp $pattern;

            print "Enter flags (i/m/s/x, or empty): ";
            my $flags = <STDIN>;
            last unless defined $flags;
            chomp $flags;
            $flags =~ s/\s+//g;

            if ($validator->add_pattern($name, $pattern, flags => $flags)) {
                print "Pattern '$name' added successfully.\n";
            }
            else {
                print "Failed to add pattern '$name'. Check errors.\n";
            }
        }
        elsif ($cmd =~ /^validate\s+(\S+)/) {
            my $name = $1;
            print "Enter string to validate: ";
            my $input = <STDIN>;
            last unless defined $input;
            chomp $input;

            my $result = $validator->validate($name, $input);
            print_result($result);
        }
        elsif ($cmd eq 'adhoc') {
            print "Enter regex pattern: ";
            my $pattern = <STDIN>;
            last unless defined $pattern;
            chomp $pattern;

            print "Enter flags (i/m/s/x, or empty): ";
            my $flags = <STDIN>;
            last unless defined $flags;
            chomp $flags;
            $flags =~ s/\s+//g;

            print "Enter string to validate: ";
            my $input = <STDIN>;
            last unless defined $input;
            chomp $input;

            my $result = $validator->validate_adhoc($pattern, $input, flags => $flags);
            print_result($result);
        }
        elsif ($cmd eq 'errors') {
            my @errors = $validator->errors;
            if (@errors) {
                print "Recent errors:\n";
                for my $err (@errors) {
                    print "  - $err\n";
                }
            }
            else {
                print "No errors.\n";
            }
        }
        else {
            print "Unknown command. Type 'list', 'add <name>', 'validate <name>', 'adhoc', 'errors', or 'quit'.\n";
        }
        print "\n";
    }
}

sub print_result {
    my ($result) = @_;
    if ($result->{valid}) {
        print "  VALID - Input matches pattern /$result->{pattern}/\n";
        if ($result->{captures} && @{$result->{captures}}) {
            print "  Captures: " . join(', ', map { defined $_ ? "'$_'" : 'undef' } @{$result->{captures}}) . "\n";
        }
    }
    else {
        if ($result->{error}) {
            print "  ERROR - $result->{error}\n";
        }
        else {
            print "  INVALID - Input does not match pattern /$result->{pattern}/\n";
        }
    }
}

