sub run_demo {
    my ($validator) = @_;

    print "=" x 60, "\n";
    print "Flexible Validation System - Demo\n";
    print "=" x 60, "\n\n";

    # Test cases
    my @tests = (
        ['email',    'user@example.com',       1],
        ['email',    'invalid-email',           0],
        ['email',    'test.user+tag@mail.co',   1],
        ['phone',    '+14155551234',            1],
        ['phone',    '123',                     0],
        ['phone',    '+442071234567',           1],
        ['zipcode',  '90210',                   1],
        ['zipcode',  '90210-1234',              1],
        ['zipcode',  '9021',                    0],
        ['ipv4',     '192.168.1.1',             1],
        ['ipv4',     '256.1.1.1',               0],
        ['ipv4',     '10.0.0.255',              1],
        ['username', 'john_doe',                1],
        ['username', '1invalid',                0],
        ['username', 'ab',                      0],
        ['url',      'https://www.example.com', 1],
        ['url',      'ftp://invalid',           0],
        ['date_iso', '2024-01-15',              1],
        ['date_iso', '2024-13-01',              0],
        ['hex_color','#ff5733',                 1],
        ['hex_color','#xyz',                    0],
    );

    my ($pass, $fail) = (0, 0);

    printf "%-12s %-30s %-10s %-10s\n", "Pattern", "Input", "Expected", "Result";
    print "-" x 65, "\n";

    for my $test (@tests) {
        my ($name, $input, $expected) = @$test;
        my $result = $validator->validate($name, $input);
        my $ok = ($result->{valid} == $expected);
        $ok ? $pass++ : $fail++;

        printf "%-12s %-30s %-10s %-10s %s\n",
            $name,
            (length($input) > 28 ? substr($input, 0, 25) . '...' : $input),
            ($expected ? 'VALID' : 'INVALID'),
            ($result->{valid} ? 'VALID' : 'INVALID'),
            ($ok ? 'PASS' : '** FAIL **');
    }

    print "\n", "-" x 65, "\n";
    print "Results: $pass passed, $fail failed out of " . scalar(@tests) . " tests\n\n";

    # Demonstrate security: attempt to inject code via pattern
    print "Security Tests:\n";
    print "-" x 65, "\n";

    my @evil_patterns = (
        ['code_exec',    '(?{ system("echo pwned") })',  'Embedded code execution'],
        ['code_exec2',   '(??{ `ls` })',                 'Postponed code execution'],
        ['too_long',     'a' x 600,                      'Excessively long pattern'],
    );

    for my $evil (@evil_patterns) {
        my ($name, $pattern, $desc) = @$evil;
        print "  Testing: $desc\n";
        print "  Pattern: $pattern\n";
        my $ok = $validator->add_pattern($name, $pattern);
        if ($ok) {
            print "  Result: COMPILED (unexpected)\n";
        }
        else {
            print "  Result: BLOCKED (as expected)\n";
        }
        print "\n";
    }

    # Ad-hoc validation demo
    print "Ad-hoc Validation Demo:\n";
    print "-" x 65, "\n";

    my $result = $validator->validate_adhoc(
        '^(\d{3})-(\d{3})-(\d{4})$',
        '555-123-4567'
    );
    printf "  Pattern: %s\n", $result->{pattern};
    printf "  Input:   %s\n", $result->{input};
    printf "  Valid:   %s\n", ($result->{valid} ? 'YES' : 'NO');
    if ($result->{captures} && @{$result->{captures}}) {
        printf "  Captures: %s\n", join(', ', map { "'$_'" } @{$result->{captures}});
    }
}

