        $tests_run++;
        my $long_input = 'a' x 20000;
        my $result = $validator->validate('case_test', $long_input);
        if (!$result->{valid} && $result->{error} =~ /maximum length/) {
            $tests_passed++;
            print "  PASS: Input length limit enforced\n";
        } else {
            print "  FAIL: Input length limit enforced\n";
        }
    }

    # Test 14: Multiple flags
    {
        $tests_run++;
        $validator->add_pattern('multi_flag', '^hello  world$', flags => 'ix');
        my $result = $validator->validate('multi_flag', 'HELLOWORLD');
        if ($result->{valid}) {
            $tests_passed++;
            print "  PASS: Multiple flags (ix)\n";
        } else {
            print "  FAIL: Multiple flags (ix)\n";
        }
    }

    # Test 15: Pattern listing
    {
        $tests_run++;
        my @names = $validator->list_patterns;
        if (scalar(@names) > 0) {
            $tests_passed++;
            print "  PASS: Pattern listing\n";
        } else {
            print "  FAIL: Pattern listing\n";
        }
    }

    print "\n" . "=" x 40 . "\n";
    print "Tests: $tests_passed/$tests_run passed\n";
    print($tests_passed == $tests_run ? "All tests passed!\n" : "Some tests failed!\n");
}